   246→absl::optional<std::chrono::milliseconds>
   247→RetryStateImpl::parseResetInterval(const Http::ResponseHeaderMap& response_headers) const {
   248→  for (const auto& reset_header : reset_headers_) {
   249→    const auto& interval = reset_header->parseInterval(time_source_, response_headers);
   250→    if (interval.has_value() && interval.value() <= reset_max_interval_) {
